const express = require('express');
const axios = require('axios');
const morgan = require('morgan');

const app = express();

app.use(express.json({ limit: '10mb' }));
app.use(express.urlencoded({ extended: true }));

morgan.token('api_key', (req) => req.query.api_key || '-');
app.use(morgan(':method :url :status :response-time ms api_key=:api_key'));

const serviceMap = {
  users: process.env.USERS_SERVICE_URL || 'http://localhost:3001',
  orders: process.env.ORDERS_SERVICE_URL || 'http://localhost:3002',
  inventory: process.env.INVENTORY_SERVICE_URL || 'http://localhost:3003'
};

app.use('/api/:service', async (req, res) => {
  const { service } = req.params;
  const baseUrl = serviceMap[service];

  if (!baseUrl) {
    return res.status(404).json({ error: 'Unknown service' });
  }

  const apiKey = req.query.api_key;
  if (!apiKey) {
    return res.status(401).json({ error: 'Missing api_key' });
  }

  const path = req.originalUrl.replace(`/api/${service}`, '');
  const targetUrl = `${baseUrl}${path}`;

  const headers = {
    ...req.headers,
    'x-api-key': apiKey,
    host: undefined
  };

  try {
    const response = await axios({
      method: req.method,
      url: targetUrl,
      headers,
      data: req.body,
      validateStatus: () => true
    });

    Object.entries(response.headers).forEach(([key, value]) => {
      if (key.toLowerCase() !== 'transfer-encoding') {
        res.setHeader(key, value);
      }
    });

    res.status(response.status).send(response.data);
  } catch (error) {
    res.status(502).json({
      error: 'Bad gateway',
      details: error.message
    });
  }
});

const port = process.env.PORT || 8080;
app.listen(port, () => {
  console.log(`API gateway listening on port ${port}`);
});